class TestCryptoExtremeOversoldAmplify(unittest.TestCase):
    def test_triggers_both_extreme(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 7.6}, "ETH/USD": {"today": 7.9}}}
        fired, reason, mult = heuristic_crypto_extreme_oversold_amplify(stats)
        self.assertTrue(fired)
        self.assertEqual(mult, 2.0)
        self.assertIn("EXTREME", reason)
    def test_no_trigger_one_above_threshold(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 7.6}, "ETH/USD": {"today": 20}}}
        fired, _, _ = heuristic_crypto_extreme_oversold_amplify(stats)
        self.assertFalse(fired)
    def test_no_trigger_normal_market(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 55}, "ETH/USD": {"today": 52}}}
        fired, _, _ = heuristic_crypto_extreme_oversold_amplify(stats)
        self.assertFalse(fired)
    def test_fail_soft_missing_rsi_data(self):
        fired, _, _ = heuristic_crypto_extreme_oversold_amplify({})
        self.assertFalse(fired)
    def test_boundary_exactly_15(self):
        stats = {"rsi_snapshot": {"BTC/USD": {"today": 15}, "ETH/USD": {"today": 15}}}
        fired, _, mult = heuristic_crypto_extreme_oversold_amplify(stats)
        self.assertTrue(fired)
        self.assertEqual(mult, 2.0)
